const sdat_table *online_get_table(const char*f,const char*p){ if(!f||!p)return 0; if(!strcmp(f,"original-cdt-table")){ if(!strcmp(p,"frodo640"))return &original_cdt_table_frodo640; if(!strcmp(p,"frodo976"))return &original_cdt_table_frodo976; if(!strcmp(p,"frodo1344"))return &original_cdt_table_frodo1344; } if(!strcmp(f,"sda-table")){ if(!strcmp(p,"falcon"))return &sda_table_falcon_base; if(!strcmp(p,"frodo640"))return &sda_table_frodo640; if(!strcmp(p,"frodo976"))return &sda_table_frodo976; if(!strcmp(p,"frodo1344"))return &sda_table_frodo1344; } return 0; }
int online_table_validate(const sdat_table*t){ if(!t||!t->available)return -1; if(t->value_type==SDAT_TYPE_U16){const uint16_t*p=t->pmf,*c=t->thresholds; uint32_t s=0; for(size_t i=0;i<t->mass_count;i++){s+=p[i]; if(c[i]!=(uint16_t)s)return -2;} return s==t->denominator_u64?0:-3;} if(t->value_type==SDAT_TYPE_U72){sdat_u72 s={0,0}; const sdat_u72*p=t->pmf,*c=t->thresholds; for(size_t i=0;i<t->mass_count;i++){uint64_t old=s.lo; s.lo+=p[i].lo; s.hi=(uint8_t)(s.hi+p[i].hi+(s.lo<old)); if(sdat_u72_cmp(s,c[i]))return -4;} return sdat_u72_cmp(s,t->denominator_u72);} return -9; }
static sdat_avx2_stats st; const sdat_avx2_stats *online_avx2_stats(void){return &st;} void online_avx2_stats_reset(void){memset(&st,0,sizeof st);} void online_avx2_stats_add(uint64_t b,uint64_t v,uint64_t tail,uint64_t fb){st.api_calls++;st.avx2_vector_batches+=b;st.avx2_vectorized_samples+=v;st.scalar_tail_samples+=tail;st.fallback_samples+=fb;}
